import logging
import logging.handlers
import os
from pathlib import Path

# Create log directory if it doesn't exist
log_dir = Path('/var/log/application')
log_dir.mkdir(parents=True, exist_ok=True)

# Define log format
log_format = logging.Formatter(
    fmt='%(asctime)s - %(name)s - %(levelname)s - [%(filename)s:%(lineno)d] - %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S'
)

# Detailed format for debug logs
detailed_format = logging.Formatter(
    fmt='%(asctime)s - %(name)s - %(levelname)s - [%(process)d:%(thread)d] - [%(filename)s:%(funcName)s:%(lineno)d] - %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S'
)

# JSON format for structured logging
json_format = logging.Formatter(
    fmt='{"timestamp": "%(asctime)s", "name": "%(name)s", "level": "%(levelname)s", "process": %(process)d, "thread": %(thread)d, "file": "%(filename)s", "function": "%(funcName)s", "line": %(lineno)d, "message": "%(message)s"}',
    datefmt='%Y-%m-%d %H:%M:%S'
)

# General application log - rotates daily, keeps 30 days
general_handler = logging.handlers.TimedRotatingFileHandler(
    filename=log_dir / 'application.log',
    when='midnight',
    interval=1,
    backupCount=30,
    encoding='utf-8',
    utc=True
)
general_handler.setLevel(logging.INFO)
general_handler.setFormatter(log_format)

# Error log - rotates daily, keeps 90 days
error_handler = logging.handlers.TimedRotatingFileHandler(
    filename=log_dir / 'error.log',
    when='midnight',
    interval=1,
    backupCount=90,
    encoding='utf-8',
    utc=True
)
error_handler.setLevel(logging.ERROR)
error_handler.setFormatter(detailed_format)

# Debug log - rotates when reaches 100MB, keeps 5 files
debug_handler = logging.handlers.RotatingFileHandler(
    filename=log_dir / 'debug.log',
    maxBytes=100 * 1024 * 1024,
    backupCount=5,
    encoding='utf-8'
)
debug_handler.setLevel(logging.DEBUG)
debug_handler.setFormatter(detailed_format)

# Access log - rotates daily, keeps 14 days
access_handler = logging.handlers.TimedRotatingFileHandler(
    filename=log_dir / 'access.log',
    when='midnight',
    interval=1,
    backupCount=14,
    encoding='utf-8',
    utc=True
)
access_handler.setLevel(logging.INFO)
access_handler.setFormatter(log_format)

# Audit log - rotates daily, keeps 365 days
audit_handler = logging.handlers.TimedRotatingFileHandler(
    filename=log_dir / 'audit.log',
    when='midnight',
    interval=1,
    backupCount=365,
    encoding='utf-8',
    utc=True
)
audit_handler.setLevel(logging.INFO)
audit_handler.setFormatter(json_format)

# Performance log - rotates when reaches 50MB, keeps 10 files
performance_handler = logging.handlers.RotatingFileHandler(
    filename=log_dir / 'performance.log',
    maxBytes=50 * 1024 * 1024,
    backupCount=10,
    encoding='utf-8'
)
performance_handler.setLevel(logging.INFO)
performance_handler.setFormatter(log_format)

# Security log - rotates daily, keeps 180 days
security_handler = logging.handlers.TimedRotatingFileHandler(
    filename=log_dir / 'security.log',
    when='midnight',
    interval=1,
    backupCount=180,
    encoding='utf-8',
    utc=True
)
security_handler.setLevel(logging.WARNING)
security_handler.setFormatter(json_format)

# Console handler for critical errors
console_handler = logging.StreamHandler()
console_handler.setLevel(logging.CRITICAL)
console_handler.setFormatter(log_format)

# Root logger configuration
root_logger = logging.getLogger()
root_logger.setLevel(logging.DEBUG)
root_logger.addHandler(general_handler)
root_logger.addHandler(error_handler)
root_logger.addHandler(debug_handler)
root_logger.addHandler(console_handler)

# Access logger
access_logger = logging.getLogger('access')
access_logger.setLevel(logging.INFO)
access_logger.addHandler(access_handler)
access_logger.propagate = False

# Audit logger
audit_logger = logging.getLogger('audit')
audit_logger.setLevel(logging.INFO)
audit_logger.addHandler(audit_handler)
audit_logger.propagate = False

# Performance logger
performance_logger = logging.getLogger('performance')
performance_logger.setLevel(logging.INFO)
performance_logger.addHandler(performance_handler)
performance_logger.propagate = False

# Security logger
security_logger = logging.getLogger('security')
security_logger.setLevel(logging.WARNING)
security_logger.addHandler(security_handler)
security_logger.propagate = False

# Configure specific loggers for third-party libraries
logging.getLogger('urllib3').setLevel(logging.WARNING)
logging.getLogger('requests').setLevel(logging.WARNING)
logging.getLogger('werkzeug').setLevel(logging.INFO)

def get_logger(name):
    return logging.getLogger(name)

def log_exception(logger, exc_info=True):
    logger.exception("Exception occurred", exc_info=exc_info)

def configure_file_permissions():
    for log_file in log_dir.glob('*.log*'):
        try:
            os.chmod(log_file, 0o640)
        except Exception:
            pass

configure_file_permissions()

